import{_ as a,c as i,o as t,ak as s,aq as o}from"./chunks/framework.DHLlVITf.js";const m=JSON.parse('{"title":"AireFrame Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireframe-v3-1-0.md","filePath":"aireblock-releases/aireframe-v3-1-0.md","lastUpdated":1783500766000}'),r={name:"aireblock-releases/aireframe-v3-1-0.md"};function n(l,e,c,d,u,h){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="aireframe-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+o+'"> AireFrame Release Notes</span> <a class="header-anchor" href="#aireframe-release-notes" aria-label="Permalink to “AireFrame Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 3.1.0<br><strong>Release Date:</strong> 15 July 2026</p></blockquote><h4 id="🚨-critical-fixes" tabindex="-1">🚨 Critical Fixes <a class="header-anchor" href="#🚨-critical-fixes" aria-label="Permalink to “🚨 Critical Fixes”">​</a></h4><ul><li>Fixed Dashboard Switching on iPad and Mobile (FRAME-2461)</li><li>Fixed Visualisations Getting Stuck Mid-Update (FRAME-2569)</li></ul><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Subject Banner Display Options from the Subject Launcher (FRAME-2589)</li><li>Smarter Multi-Subject View Updates (FRAME-2594)</li><li>Rebuild Progress Indicator for Visualisation Data (FRAME-2598)</li><li>Streamlined Data Extracts Table (FRAME-2602)</li><li>Configurable Data Loading for Multi-Subject Visualisations (FRAME-2605)</li><li>Early Validation on Subject Location Transfers (FRAME-2611)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Faster Data Visualisations (FRAME-2556)</li><li>Smarter Subject List Refresh Notifications (FRAME-2567)</li><li>Live Update Indicators for Structural Entity Widgets (FRAME-2575)</li><li>Faster Visualisation Cache Building (FRAME-2591)</li><li>More Reliable Dataset Rebuild Tracking (FRAME-2592)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Fixed Delayed Permission Updates (FRAME-2584)</li><li>Fixed Copy Key Button Opening Dropdown (FRAME-2593)</li><li>Fixed Subject Lists Not Refreshing When Marked Stale (FRAME-2619)</li><li>Fixed Update Icon Not Appearing on Location Changes (FRAME-2623)</li><li>Fixed Dashboard Reloading and Forms Closing on Widget Updates (FRAME-2628)</li></ul><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="🚨-critical-fixes-1" tabindex="-1">🚨 Critical Fixes <a class="header-anchor" href="#🚨-critical-fixes-1" aria-label="Permalink to “🚨 Critical Fixes”">​</a></h3><hr><h4 id="fixed-dashboard-switching-on-ipad-and-mobile-frame-2461" tabindex="-1">Fixed Dashboard Switching on iPad and Mobile (FRAME-2461) <a class="header-anchor" href="#fixed-dashboard-switching-on-ipad-and-mobile-frame-2461" aria-label="Permalink to “Fixed Dashboard Switching on iPad and Mobile (FRAME-2461)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where users on iPad and other mobile devices could not switch back to the original dashboard after selecting a different one on a subject record.</p></div><h4 id="fixed-visualisations-getting-stuck-mid-update-frame-2569" tabindex="-1">Fixed Visualisations Getting Stuck Mid-Update (FRAME-2569) <a class="header-anchor" href="#fixed-visualisations-getting-stuck-mid-update-frame-2569" aria-label="Permalink to “Fixed Visualisations Getting Stuck Mid-Update (FRAME-2569)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a fault where visualisations could become permanently stuck in a pending state if a data set update job failed without triggering a retry, leaving the visualisation refresh unresolved.</p></div><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="subject-banner-display-options-from-the-subject-launcher-frame-2589" tabindex="-1">Subject Banner Display Options from the Subject Launcher (FRAME-2589) <a class="header-anchor" href="#subject-banner-display-options-from-the-subject-launcher-frame-2589" aria-label="Permalink to “Subject Banner Display Options from the Subject Launcher (FRAME-2589)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The subject launcher now supports the <code>subjectBanner=hidden</code> and <code>subjectBanner=collapsed</code> query parameters, matching existing behaviour on the subject view.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now control whether the subject banner is shown, hidden, or collapsed when launching directly into a subject.</p></div><h4 id="smarter-multi-subject-view-updates-frame-2594" tabindex="-1">Smarter Multi-Subject View Updates (FRAME-2594) <a class="header-anchor" href="#smarter-multi-subject-view-updates-frame-2594" aria-label="Permalink to “Smarter Multi-Subject View Updates (FRAME-2594)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Improved stale subject tracking in the multi-subject view so it no longer flags subjects that aren&#39;t part of the active list, and clears stale tracking correctly when navigating between pages.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll see fewer unnecessary refreshes and more accurate &quot;out of date&quot; indicators when browsing subject lists.</p></div><h4 id="rebuild-progress-indicator-for-visualisation-data-frame-2598" tabindex="-1">Rebuild Progress Indicator for Visualisation Data (FRAME-2598) <a class="header-anchor" href="#rebuild-progress-indicator-for-visualisation-data-frame-2598" aria-label="Permalink to “Rebuild Progress Indicator for Visualisation Data (FRAME-2598)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Added state tracking so the system can indicate when a normalised data set is still being built from scratch, rather than showing incomplete data as if it were final.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll be able to tell when a visualisation is still populating, so you&#39;re not left wondering why the data looks incomplete.</p></div><h4 id="streamlined-data-extracts-table-frame-2602" tabindex="-1">Streamlined Data Extracts Table (FRAME-2602) <a class="header-anchor" href="#streamlined-data-extracts-table-frame-2602" aria-label="Permalink to “Streamlined Data Extracts Table (FRAME-2602)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Removed the &quot;used by data pipelines&quot; column from the Data Extracts table, as this information is now covered by the existing &quot;in use&quot; column.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your Data Extracts table is now simpler and free of duplicate information.</p></div><h4 id="configurable-data-loading-for-multi-subject-visualisations-frame-2605" tabindex="-1">Configurable Data Loading for Multi-Subject Visualisations (FRAME-2605) <a class="header-anchor" href="#configurable-data-loading-for-multi-subject-visualisations-frame-2605" aria-label="Permalink to “Configurable Data Loading for Multi-Subject Visualisations (FRAME-2605)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Introduced a dedicated configuration value for the page size used when fetching subject source data, decoupling it from the shared default used elsewhere in the system.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Behind the scenes, this allows performance to be fine-tuned for your tenant without affecting other areas of the platform.</p></div><h4 id="early-validation-on-subject-location-transfers-frame-2611" tabindex="-1">Early Validation on Subject Location Transfers (FRAME-2611) <a class="header-anchor" href="#early-validation-on-subject-location-transfers-frame-2611" aria-label="Permalink to “Early Validation on Subject Location Transfers (FRAME-2611)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Subject location transfers now fail immediately with a clear error if the destination location is not subject-assignable, rather than accepting the request and failing later in the background.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll get immediate feedback if a location transfer can&#39;t go ahead, instead of finding out after the fact.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="faster-data-visualisations-frame-2556" tabindex="-1">Faster Data Visualisations (FRAME-2556) <a class="header-anchor" href="#faster-data-visualisations-frame-2556" aria-label="Permalink to “Faster Data Visualisations (FRAME-2556)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Introduced a normalised visualisation data set cache, forming part of the ongoing work to improve how subject data is loaded and displayed.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your visualisations will load faster and stay more up to date as your data changes.</p></div><h4 id="smarter-subject-list-refresh-notifications-frame-2567" tabindex="-1">Smarter Subject List Refresh Notifications (FRAME-2567) <a class="header-anchor" href="#smarter-subject-list-refresh-notifications-frame-2567" aria-label="Permalink to “Smarter Subject List Refresh Notifications (FRAME-2567)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Reworked how the multi-subject list handles incoming data updates. Rather than refreshing automatically and potentially disrupting filtering or ordering, the list now shows a notification with a manual refresh option, plus a per-session toggle for automatic refresh.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll no longer lose your place in a subject list when new data arrives. You&#39;ll see a clear notice when updates are available and can choose when to refresh, with an option to turn automatic refreshing back on if you prefer it.</p></div><h4 id="live-update-indicators-for-structural-entity-widgets-frame-2575" tabindex="-1">Live Update Indicators for Structural Entity Widgets (FRAME-2575) <a class="header-anchor" href="#live-update-indicators-for-structural-entity-widgets-frame-2575" aria-label="Permalink to “Live Update Indicators for Structural Entity Widgets (FRAME-2575)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Added subscription support for pending update events on structural entity widgets, building on the reworked notification handling introduced elsewhere in this release.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Structural entity widgets will more accurately reflect when their underlying data has changed.</p></div><h4 id="faster-visualisation-cache-building-frame-2591" tabindex="-1">Faster Visualisation Cache Building (FRAME-2591) <a class="header-anchor" href="#faster-visualisation-cache-building-frame-2591" aria-label="Permalink to “Faster Visualisation Cache Building (FRAME-2591)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Normalised cache building now processes subjects in batches rather than one at a time, reducing the number of database round trips required when a visualisation data set is created from scratch.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>New visualisations should build noticeably faster, especially for tenants with larger numbers of subjects.</p></div><h4 id="more-reliable-dataset-rebuild-tracking-frame-2592" tabindex="-1">More Reliable Dataset Rebuild Tracking (FRAME-2592) <a class="header-anchor" href="#more-reliable-dataset-rebuild-tracking-frame-2592" aria-label="Permalink to “More Reliable Dataset Rebuild Tracking (FRAME-2592)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Introduced a saga to manage and track the state of normalised data sets as they are built, providing clearer visibility of build progress when a data set doesn&#39;t yet exist or is being rebuilt from scratch.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>The platform now keeps more reliable track of visualisations that are still being built, reducing the chance of incomplete or inconsistent data being shown.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="fixed-delayed-permission-updates-frame-2584" tabindex="-1">Fixed Delayed Permission Updates (FRAME-2584) <a class="header-anchor" href="#fixed-delayed-permission-updates-frame-2584" aria-label="Permalink to “Fixed Delayed Permission Updates (FRAME-2584)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where changes to a user&#39;s role were not reflected in AireFrame in a timely manner, sometimes requiring an overnight cache invalidation before the correct permissions took effect.</p></div><h4 id="fixed-copy-key-button-opening-dropdown-frame-2593" tabindex="-1">Fixed Copy Key Button Opening Dropdown (FRAME-2593) <a class="header-anchor" href="#fixed-copy-key-button-opening-dropdown-frame-2593" aria-label="Permalink to “Fixed Copy Key Button Opening Dropdown (FRAME-2593)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a visual bug where clicking &quot;copy key&quot; on custom fields incorrectly opened the associated dropdown.</p></div><h4 id="fixed-subject-lists-not-refreshing-when-marked-stale-frame-2619" tabindex="-1">Fixed Subject Lists Not Refreshing When Marked Stale (FRAME-2619) <a class="header-anchor" href="#fixed-subject-lists-not-refreshing-when-marked-stale-frame-2619" aria-label="Permalink to “Fixed Subject Lists Not Refreshing When Marked Stale (FRAME-2619)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where subject list widget data remained marked as stale in the database and was not requeued after a manual cache refresh from Dashboards &amp; Data.</p></div><h4 id="fixed-update-icon-not-appearing-on-location-changes-frame-2623" tabindex="-1">Fixed Update Icon Not Appearing on Location Changes (FRAME-2623) <a class="header-anchor" href="#fixed-update-icon-not-appearing-on-location-changes-frame-2623" aria-label="Permalink to “Fixed Update Icon Not Appearing on Location Changes (FRAME-2623)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where the update-available icon did not appear when a subject was added to or removed from a location.</p></div><h4 id="fixed-dashboard-reloading-and-forms-closing-on-widget-updates-frame-2628" tabindex="-1">Fixed Dashboard Reloading and Forms Closing on Widget Updates (FRAME-2628) <a class="header-anchor" href="#fixed-dashboard-reloading-and-forms-closing-on-widget-updates-frame-2628" aria-label="Permalink to “Fixed Dashboard Reloading and Forms Closing on Widget Updates (FRAME-2628)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where a widget update caused the whole page to reload, closing any open forms. Subject list paging no longer resets the page scroll position when this occurs.</p></div>',66)])])}const b=a(r,[["render",n]]);export{m as __pageData,b as default};
